mapper.select:
select p.id, p.name, p.category_id as categoryId, c.name as categoryName, p.price, p.image, p.description, sum(case when then (ib.stock_quantity - ib.locked_quantity - ib.sold_quantity) else 0 end) as availableQuantity, ( select ib2.id from inventory_batch ib2 where ib2.product_id = p.id and ib2.status = 1 and ib2.expiration_time >= now() and (ib2.stock_quantity - ib2.locked_quantity - ib2.sold_quantity) > 0 order by ib2.expiration_time asc, ib2.id asc limit 1 ) as recommendedBatchId, case when ( select ib2.expiration_time from inventory_batch ib2 where ib2.product_id = p.id and ib2.status = 1 and ib2.expiration_time >= now() and (ib2.stock_quantity - ib2.locked_quantity - ib2.sold_quantity) > 0 order by ib2.expiration_time asc, ib2.id asc limit 1 ) is null then 1 else 0 end as expiration_sort_priority, ( select ib2.expiration_time from inventory_batch ib2 where ib2.product_id = p.id and ib2.status = 1 and ib2.expiration_time >= now() and (ib2.stock_quantity - ib2.locked_quantity - ib2.sold_quantity) > 0 order by ib2.expiration_time asc, ib2.id asc limit 1 ) as nearest_expiration_time from product p inner join category c on c.id = p.category_id left join inventory_batch ib on ib.product_id = p.id
p.status = 1 and c.type = 1 and c.status = 1 and
and p.name like concat('%', #{criteria.keyword}, '%')
and p.category_id = #{criteria.categoryId}
group by p.id, p.name, p.category_id, c.name, p.price, p.image, p.description, p.update_time order by ${criteria.sortColumn} ${criteria.sortDirection}, p.id desc limit #{criteria.limit} offset #{criteria.offset}

select p.id, p.name, p.category_id as categoryId, c.name as categoryName, p.price, p.image, p.description, sum(case when then (ib.stock_quantity - ib.locked_quantity - ib.sold_quantity) else 0 end) as availableQuantity, ( select ib2.id from inventory_batch ib2 where ib2.product_id = p.id and ib2.status = 1 and ib2.expiration_time >= current_timestamp() and (ib2.stock_quantity - ib2.locked_quantity - ib2.sold_quantity) > 0 order by ib2.expiration_time asc, ib2.id asc limit 1 ) as recommendedBatchId, case when ( select ib2.expiration_time from inventory_batch ib2 where ib2.product_id = p.id and ib2.status = 1 and ib2.expiration_time >= current_timestamp() and (ib2.stock_quantity - ib2.locked_quantity - ib2.sold_quantity) > 0 order by ib2.expiration_time asc, ib2.id asc limit 1 ) is null then 1 else 0 end as expiration_sort_priority, ( select ib2.expiration_time from inventory_batch ib2 where ib2.product_id = p.id and ib2.status = 1 and ib2.expiration_time >= current_timestamp() and (ib2.stock_quantity - ib2.locked_quantity - ib2.sold_quantity) > 0 order by ib2.expiration_time asc, ib2.id asc limit 1 ) as nearest_expiration_time from product p inner join category c on c.id = p.category_id left join inventory_batch ib on ib.product_id = p.id
p.status = 1 and c.type = 1 and c.status = 1 and
and p.name like concat('%', #{criteria.keyword}, '%')
and p.category_id = #{criteria.categoryId}
group by p.id, p.name, p.category_id, c.name, p.price, p.image, p.description, p.update_time order by ${criteria.sortColumn} ${criteria.sortDirection}, p.id desc limit #{criteria.limit} offset #{criteria.offset}
